// portal-a25-ingresos — validar_firma_ts_rol.
// Recomputa HMAC-SHA256 sobre los bytes EXACTOS (D-C-29). Revalida ts (300s), rol
// (allowlist, D-C-39), action binding (D-C-41) y -A25- el payload de periodo (2da defensa).
const crypto = require('crypto');

const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';
if (!SECRET || SECRET.startsWith('__PEGAR_')) {
  throw new Error('VITA_HMAC_SECRET no configurado en n8n Variables; abortando (assert duro).');
}

const item = $input.first();
const wh = item.json;

function rej(motivo, b) {
  return [{ json: { ok_firma: false, motivo,
    ambiente_esperado: (b && b.ambiente_esperado) ?? null,
    rol: (b && b.rol) ?? null, action: (b && b.action) ?? null,
    ts: (b && b.ts) ?? null, payload_norm: null } }];
}

// 1) Raw body como Buffer EXACTO. Prioridad: binario 'data'. Fallback: wh.rawBody (L-C-05).
let buf = null;
try {
  if (item.binary && item.binary.data) {
    buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  }
} catch (e) {
  buf = null;
}
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) return rej('raw_body_ausente', null);

// 2) Firma del header.
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';

// 3) HMAC recomputado sobre los MISMOS bytes.
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(buf).digest('hex');

// 4) Comparacion timing-safe.
let firmaOk = false;
try {
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  firmaOk = false;
}
if (!firmaOk) return rej('firma_invalida', null);

// 5) Parseo (firma ya validada sobre bytes crudos).
let body;
try {
  body = JSON.parse(buf.toString('utf8'));
} catch (e) {
  return rej('payload_invalido', null);
}

// 6) Ventana de ts (D-C-29): |now - ts| <= 300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) {
  return rej('ts_fuera_de_ventana', { ...body, ts: body.ts });
}
body.ts = ts;

// 7) Allowlist de rol (D-C-39). A25 = vicky/socio (sin jenny, D-C-03/27).
const ROLES_OK = ['vicky', 'socio'];
if (!ROLES_OK.includes(body.rol)) return rej('rol_no_permitido', body);

// 8) Action binding (D-C-41): EXPECTED_ACTION = ingresos.cobrados_periodo (A25).
const EXPECTED_ACTION = 'ingresos.cobrados_periodo';
if (body.action !== EXPECTED_ACTION) return rej('accion_desconocida', body);

// 9) Payload A25. Reject-unknown + normalizacion. Floor 2026-07-01 (D-NEG-02) clampea
//    periodo_desde (el SQL ademas lo impone con GREATEST). periodo_hasta HIBRIDO:
//      - OMITIDO -> hoy (CURRENT_DATE). SIN check de inversion: con floor futuro queda
//        periodo_desde>periodo_hasta -> la query devuelve vacio con ok:true (totales 0).
//      - EXPLICITO -> YMD y, tras el clamp, >= periodo_desde; sino payload_invalido.
const FLOOR = '2026-07-01';
const PERMITIDAS = ['periodo_desde', 'periodo_hasta', 'limit', 'offset'];

let pl = {};
if (body.payload === undefined || body.payload === null) {
  pl = {};
} else if (typeof body.payload === 'object' && !Array.isArray(body.payload)) {
  pl = body.payload;
} else {
  return rej('payload_invalido', body);
}
for (const k of Object.keys(pl)) {
  if (!PERMITIDAS.includes(k)) return rej('payload_invalido', body);
}

function isYMD(s) {
  if (typeof s !== 'string' || !/^\d{4}-\d{2}-\d{2}$/.test(s)) return false;
  const Y = +s.slice(0, 4), M = +s.slice(5, 7), D = +s.slice(8, 10);
  if (M < 1 || M > 12 || D < 1 || D > 31) return false;
  const dt = new Date(Date.UTC(Y, M - 1, D));
  return dt.getUTCFullYear() === Y && dt.getUTCMonth() === M - 1 && dt.getUTCDate() === D;
}
function todayYMD() { return new Date().toISOString().slice(0, 10); }

// periodo_desde: opcional; YMD; clamp al floor. Default = floor.
let periodo_desde = FLOOR;
if (pl.periodo_desde !== undefined && pl.periodo_desde !== null) {
  if (!isYMD(pl.periodo_desde)) return rej('payload_invalido', body);
  periodo_desde = (pl.periodo_desde < FLOOR) ? FLOOR : pl.periodo_desde;
}

// periodo_hasta: hibrido (ver arriba).
let periodo_hasta;
const hastaExplicito = (pl.periodo_hasta !== undefined && pl.periodo_hasta !== null);
if (hastaExplicito) {
  if (!isYMD(pl.periodo_hasta)) return rej('payload_invalido', body);
  if (pl.periodo_hasta < periodo_desde) return rej('payload_invalido', body); // inversion explicita
  periodo_hasta = pl.periodo_hasta;
} else {
  periodo_hasta = todayYMD(); // floor futuro -> periodo_desde>periodo_hasta -> vacio OK
}

// limit: opcional; entero; clamp [1,200]; default 50.
let limit = 50;
if (pl.limit !== undefined && pl.limit !== null) {
  if (typeof pl.limit !== 'number' || !Number.isSafeInteger(pl.limit)) return rej('payload_invalido', body);
  limit = Math.min(Math.max(pl.limit, 1), 200);
}

// offset: opcional; entero >= 0; default 0.
let offset = 0;
if (pl.offset !== undefined && pl.offset !== null) {
  if (typeof pl.offset !== 'number' || !Number.isSafeInteger(pl.offset) || pl.offset < 0) return rej('payload_invalido', body);
  offset = pl.offset;
}

const payload_norm = { periodo_desde, periodo_hasta, limit, offset };

return [{ json: { ok_firma: true, motivo: null,
  ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null,
  action: body.action ?? null, ts, payload_norm } }];

// portal-a25-ingresos — verificar_acceso. Compara ambiente y arma el envelope de rechazo
// (D-C-18/35). En exito marca {ok:true}; el envelope final de exito lo arma el render.
const v = $('validar_firma_ts_rol').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;

function envErr(code, message, detail) {
  return [{ json: { ok: false, error: { code, message, detail: detail ?? null } } }];
}

if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'payload invalido (periodo mal formado, inversion explicita o clave no permitida)',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)',
    rol_no_permitido: 'rol no habilitado para esta accion',
    accion_desconocida: 'accion no corresponde a este endpoint'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}

if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}

return [{ json: { ok: true } }];

// ===== portal-a25-ingresos — render JSON (caja percibida) =====
// total_cobrado = SOLO sena+saldo confirmados (D-9G-03). otros_movimientos (extra/ajuste/
// reembolso) INFORMATIVO: no suma, no neto, no cascada, no matriz, no reabre Carril B (D-C-27).
// Suma sobre pagos (incluye residuo); cabana por LEFT JOIN (null en residuo). Montos sumados
// en CENTAVOS (sin float drift). filas paginadas (sena+saldo); total = cantidad de pagos
// sena+saldo (pager). IDs BIGINT -> numero (C2). Periodo vacio -> totales 0, arrays [], ok:true.
function safeAll(nodeName, keyField) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    const rows = items.map(it => it.json).filter(j => j && j[keyField] !== undefined && j[keyField] !== null);
    return { ok: true, rows };
  } catch (e) { return { ok: false, rows: [] }; }
}
function num(v) { if (v === null || v === undefined || v === '') return null; const n = Number(v); return Number.isFinite(n) ? n : null; }
function int0(v) { const n = Number(v); return Number.isFinite(n) ? Math.trunc(n) : 0; }
function centsOf(v) { const n = Number(v); return Number.isFinite(n) ? Math.round(n * 100) : 0; }

const r = safeAll('PG: leer ingresos', 'id_pago');
if (!r.ok) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar los ingresos', detail: null } } }];
}

const pn = $('validar_firma_ts_rol').first().json.payload_norm || {};
const limit = int0(pn.limit);
const offset = int0(pn.offset);

const esCaja = (t) => t === 'sena' || t === 'saldo';
const esOtro = (t) => t === 'extra' || t === 'ajuste' || t === 'reembolso';
const caja = r.rows.filter(x => esCaja(x.tipo));
const otros = r.rows.filter(x => esOtro(x.tipo));

function agrupar(rows, key) {
  const m = new Map();
  for (const x of rows) {
    const k = x[key];
    const cur = m.get(k) || { c: 0, n: 0 };
    cur.c += centsOf(x.monto_recibido);
    cur.n += 1;
    m.set(k, cur);
  }
  return m;
}
function salida(m, keyName) {
  const out = [];
  for (const [k, v] of m) out.push({ [keyName]: k, monto: v.c / 100, n: v.n });
  return out;
}

let totalC = 0;
for (const x of caja) totalC += centsOf(x.monto_recibido);
const total_cobrado = totalC / 100;
const total = caja.length;

const por_tipo  = salida(agrupar(caja, 'tipo'), 'tipo');
const por_medio = salida(agrupar(caja, 'medio_pago'), 'medio_pago');
const por_mes   = salida(agrupar(caja, 'mes'), 'mes');
const otros_por_tipo = salida(agrupar(otros, 'tipo'), 'tipo');

const filasAll = caja.map(x => ({
  id_pago: int0(x.id_pago),
  id_reserva: (x.id_reserva !== null && x.id_reserva !== undefined) ? int0(x.id_reserva) : null,
  cabana: x.cabana ?? null,
  tipo: x.tipo,
  medio_pago: x.medio_pago,
  monto: num(x.monto_recibido),
  created_at: x.created_at,
  validado_en: x.validado_en ?? null
}));
const filas = filasAll.slice(offset, offset + limit);

return [{ json: { ok: true, data: {
  periodo_desde: pn.periodo_desde ?? null,
  periodo_hasta: pn.periodo_hasta ?? null,
  total_cobrado,
  total,
  por_tipo,
  por_medio,
  por_mes,
  otros_movimientos: { por_tipo: otros_por_tipo },
  filas,
  limit,
  offset
} } }];
